import React from "react";
import styles from "./nav-bar.module.css";
import NavButton from "../nav-button";
import { useState } from "react";

const NavBar = () => {
  const [activeDropdown, setActiveDropdown] = useState("");

  function toggleDropdown(openDropdown) {
    let option =
      activeDropdown === openDropdown
        ? setActiveDropdown("")
        : setActiveDropdown(openDropdown);
  }

  const obj1 = {
    title: "Discovery",
    content: ["Placeholder", "Placeholder", "Placeholder"],
  };

  const dropDownObjectEx = [obj1];

  // const obj2 = {
  //   title: "About",
  //   content: ["Something", "Something", "Something"],
  // };
  // const dropDownObjectEx2 = [obj2];

  return (
    <>
      <div className={styles.nav__bar}>
        <NavButton
          text="Discovery"
          imgSrc="/images/ChevronDown.png"
          handleClick={() => toggleDropdown("Discovery")}
        />
        <NavButton text="About" isLink={true} />
        <NavButton text="Contact us" isLink={true} />
      </div>
      <MegaMenu
        dropDownObject={dropDownObjectEx}
        show={activeDropdown === "Foods"}
      />
    </>
  );
};

export default NavBar;

